import React, { useState, useRef, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import { LogoMark } from '../components/Logo';
import s from './Chat.module.css';

const EXAMPLES = [
  'Azul, matta tgim ?',
  'Acu yettimna tafukt ?',
  'Ssalam o 3alaykom',
  'Lmed iyi tmazight',
  'Tanmmirt !',
  'Mani smnk ?',
];

export default function Chat() {
  const { user, logout } = useAuth();
  const nav = useNavigate();

  // ── État principal ──────────────────────────────────────────────────────
  const [conversations, setConversations] = useState([]);      // liste sidebar
  const [activeConvId, setActiveConvId] = useState(null);      // conv active
  const [messages, setMessages] = useState([]);                // messages affichés
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(true);

  const messagesEndRef = useRef(null);
  const textareaRef   = useRef(null);

  // ── Charger les conversations au démarrage ─────────────────────────────
  useEffect(() => { loadConversations(); }, []);

  const loadConversations = async () => {
    try {
      const r = await axios.get('/conversations');
      setConversations(r.data.conversations || []);
    } catch { /* silencieux */ }
  };

  // ── Charger les messages d'une conversation ────────────────────────────
  const loadConversation = async (convId) => {
    try {
      const r = await axios.get(`/conversations/${convId}/messages`);
      const raw = r.data.messages || [];
      setMessages(raw.map(m => ({
        role:      m.sender === 'user' ? 'user' : 'bot',
        text:      m.content,
        time:      m.timestamp ? new Date(m.timestamp).toLocaleTimeString('fr-FR', { hour:'2-digit', minute:'2-digit' }) : '',
        id:        m.id,
      })));
      setActiveConvId(convId);
    } catch { /* silencieux */ }
  };

  // ── Nouvelle conversation ──────────────────────────────────────────────
  const newConversation = () => {
    setActiveConvId(null);
    setMessages([]);
    textareaRef.current?.focus();
  };

  // ── Scroll automatique ─────────────────────────────────────────────────
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, loading]);

  // ── Auto-resize textarea ───────────────────────────────────────────────
  const handleInputChange = e => {
    setInput(e.target.value);
    const el = textareaRef.current;
    if (el) { el.style.height = 'auto'; el.style.height = Math.min(el.scrollHeight, 140) + 'px'; }
  };

  // ── Envoyer un message ─────────────────────────────────────────────────
  const sendMessage = useCallback(async () => {
    const text = input.trim();
    if (!text || loading) return;

    const now = new Date().toLocaleTimeString('fr-FR', { hour:'2-digit', minute:'2-digit' });

    // Afficher immédiatement le message utilisateur
    setMessages(prev => [...prev, { role: 'user', text, time: now }]);
    setInput('');
    if (textareaRef.current) textareaRef.current.style.height = 'auto';
    setLoading(true);

    try {
      const r = await axios.post('/chat', {
        message:         text,
        conversation_id: activeConvId,
      });

      const botTime = new Date().toLocaleTimeString('fr-FR', { hour:'2-digit', minute:'2-digit' });
      setMessages(prev => [...prev, {
        role: 'bot',
        text: r.data.response,
        time: botTime,
        id:   r.data.message_id,
      }]);

      // Mettre à jour la conv active
      if (!activeConvId && r.data.conversation_id) {
        setActiveConvId(r.data.conversation_id);
        loadConversations(); // rafraîchir la sidebar
      }
    } catch (err) {
      const errTime = new Date().toLocaleTimeString('fr-FR', { hour:'2-digit', minute:'2-digit' });
      setMessages(prev => [...prev, {
        role: 'bot',
        text: 'Γalaṭ: ur yeẓẓi ara backend. Senqed tiliγri-ik.',
        time: errTime,
        isError: true,
      }]);
    } finally {
      setLoading(false);
    }
  }, [input, loading, activeConvId]);

  const handleKeyDown = e => {
    if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); sendMessage(); }
  };

  const useExample = txt => {
    setInput(txt);
    textareaRef.current?.focus();
  };

  const handleLogout = () => { logout(); nav('/'); };

  const deleteConv = async (convId, e) => {
    e.stopPropagation();
    try {
      await axios.delete(`/conversations/${convId}`);
      if (activeConvId === convId) newConversation();
      loadConversations();
    } catch { /* silencieux */ }
  };

  // ── Render ─────────────────────────────────────────────────────────────
  return (
    <div className={s.layout}>
      {/* ── Sidebar ── */}
      <aside className={`${s.sidebar} ${sidebarOpen ? s.sideOpen : ''}`}>
        <div className={s.sideTop}>
          <div className={s.sideLogoRow}>
            <LogoMark size={28} />
            <span className={s.sideLogoTxt}>AWAL GPT</span>
            <button className={s.sideToggle} onClick={() => setSidebarOpen(v => !v)}>
              ←
            </button>
          </div>
          <button className={s.newChatBtn} onClick={newConversation}>
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
              <line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/>
            </svg>
            Nouvelle conversation
          </button>
        </div>

        {/* Exemples */}
        <div className={s.sideSection}>
          <div className={s.sideSectionTitle}>Essayer</div>
          {EXAMPLES.map((ex, i) => (
            <button key={i} className={s.exampleBtn} onClick={() => useExample(ex)}>
              {ex}
            </button>
          ))}
        </div>

        {/* Historique */}
        {conversations.length > 0 && (
          <div className={s.sideSection}>
            <div className={s.sideSectionTitle}>Historique</div>
            {conversations.map(c => (
              <div key={c.id}
                className={`${s.convItem} ${activeConvId === c.id ? s.convActive : ''}`}
                onClick={() => loadConversation(c.id)}>
                <span className={s.convTitle}>{c.title || 'Conversation'}</span>
                <button className={s.convDel} onClick={e => deleteConv(c.id, e)} title="Supprimer">×</button>
              </div>
            ))}
          </div>
        )}

        {/* Utilisateur */}
        <div className={s.sideFooter}>
          <div className={s.userRow}>
            <div className={s.userAvatar}>{user?.username?.[0]?.toUpperCase() || 'U'}</div>
            <div className={s.userInfo}>
              <div className={s.userName}>{user?.username}</div>
              <div className={s.userEmail}>{user?.email}</div>
            </div>
          </div>
          <button className={s.logoutBtn} onClick={handleLogout}>Déconnexion</button>
        </div>
      </aside>

      {/* ── Zone principale ── */}
      <main className={s.main}>
        {/* Header minimal */}
        <div className={s.mainHeader}>
          {!sidebarOpen && (
            <button className={s.sideToggleMain} onClick={() => setSidebarOpen(true)}>☰</button>
          )}
          <div className={s.mainHeaderTitle}>
            <LogoMark size={24} />
            <span>AWAL GPT</span>
          </div>
          {activeConvId && (
            <button className={s.newChatSmall} onClick={newConversation}>+ Nouveau</button>
          )}
        </div>

        {/* Messages */}
        <div className={s.messagesWrap}>
          <div className={s.messages}>
            {/* Écran vide */}
            {messages.length === 0 && (
              <div className={s.emptyState}>
                <LogoMark size={56} />
                <h2 className={s.emptyTitle}>Azul ! ⵣⵓⵍ</h2>
                <p className={s.emptySub}>
                  Chatbot Tamazight en écriture latine.<br />
                  Écrivez en Tamazight ci-dessous pour commencer.
                </p>
                <div className={s.emptyExamples}>
                  {EXAMPLES.slice(0, 4).map((ex, i) => (
                    <button key={i} className={s.emptyEx} onClick={() => useExample(ex)}>
                      {ex}
                    </button>
                  ))}
                </div>
              </div>
            )}

            {/* Liste des messages — PROPRE comme ChatGPT */}
            {messages.map((msg, i) => (
              <div key={i} className={`${s.msgRow} ${msg.role === 'user' ? s.msgUser : s.msgBot}`}>
                {/* Avatar */}
                <div className={s.msgAvatar}>
                  {msg.role === 'user'
                    ? <span className={s.avatarUser}>{user?.username?.[0]?.toUpperCase() || 'U'}</span>
                    : <LogoMark size={30} />
                  }
                </div>

                {/* Contenu */}
                <div className={s.msgBody}>
                  <div className={s.msgName}>
                    {msg.role === 'user' ? (user?.username || 'Vous') : 'AWAL GPT'}
                    <span className={s.msgTime}>{msg.time}</span>
                  </div>
                  <div className={`${s.msgText} ${msg.isError ? s.msgError : ''}`}>
                    {msg.text}
                  </div>
                </div>
              </div>
            ))}

            {/* Typing indicator */}
            {loading && (
              <div className={`${s.msgRow} ${s.msgBot}`}>
                <div className={s.msgAvatar}><LogoMark size={30} /></div>
                <div className={s.msgBody}>
                  <div className={s.msgName}>AWAL GPT</div>
                  <div className={s.typing}>
                    <span /><span /><span />
                  </div>
                </div>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>
        </div>

        {/* Zone de saisie — propre */}
        <div className={s.inputArea}>
          <div className={s.inputBox}>
            <textarea
              ref={textareaRef}
              className={s.textarea}
              placeholder="Aru s tmazight (ex: azul, matta tgim ?)..."
              value={input}
              onChange={handleInputChange}
              onKeyDown={handleKeyDown}
              rows={1}
              disabled={loading}
            />
            <button
              className={s.sendBtn}
              onClick={sendMessage}
              disabled={loading || !input.trim()}
            >
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none"
                stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                <line x1="22" y1="2" x2="11" y2="13"/>
                <polygon points="22 2 15 22 11 13 2 9 22 2"/>
              </svg>
            </button>
          </div>
          <p className={s.inputHint}>Entrée pour envoyer · Shift+Entrée pour saut de ligne</p>
        </div>
      </main>
    </div>
  );
}
